   364	  function normalizeAppIdentity(value) {
   365	    return normalizeAppText(value).trim().replace(/\.desktop$/, "");
   366	  }
   367	
   368	  function appIdentityAliases(value) {
   369	    const identity = normalizeAppIdentity(value);
   370	    if (identity === "")
   371	      return [];
   372	    const aliases = [identity];
   373	    let match = identity.match(/^chrome-([a-z]+)-default$/);
   374	    if (match !== null)
   375	      aliases.push("crx_" + match[1]);
   376	    match = identity.match(/^crx_([a-z]+)$/);
   377	    if (match !== null)
   378	      aliases.push("chrome-" + match[1] + "-default");
   379	    return aliases;
   380	  }
