   382	  function appToplevelFor(entry) {
   383	    const appIdentities = [];
   384	    [entry.id, entry.startupClass, entry.icon].forEach(value => {
   385	      appIdentityAliases(value).forEach(identity => {
   386	        if (!appIdentities.includes(identity))
   387	          appIdentities.push(identity);
   388	      });
   389	    });
   390	    if (appIdentities.length === 0)
   391	      return null;
