   368	  function appIdentityAliases(value) {
   369	    const identity = normalizeAppIdentity(value);
   370	    if (identity === "")
   371	      return [];
   372	    const aliases = [identity];
   373	    let match = identity.match(/^chrome-([a-z]+)-default$/);
   374	    if (match !== null)
   375	      aliases.push("crx_" + match[1]);
   376	    match = identity.match(/^crx_([a-z]+)$/);
   377	    if (match !== null)
