+
+  onPresentedChanged: {
+    if (presented) {
+      contentOffset = -18;
+      contentBounce.restart();
+    } else {
+      contentBounce.stop();
+      contentOffset = 0;
+    }
+  }
+
+  Connections {
+    target: statusData
