  79	    device.type === DeviceType.Wifi) ?? null
  80	  readonly property var wiredDevice: Networking.devices.values.find(device =>
  81	    device.type === DeviceType.Wired && device.connected) ?? null
  82	  readonly property var wifiNetworks: {
